+func TestEnsureVisible(t *testing.T) {
+	state := &appState{lastRows: 10, selected: 8, scroll: 0}
+	ensureVisible(state)
+	if state.scroll == 0 {
+		t.Fatalf("scroll should advance")
+	}
+	state.selected = 0
+	ensureVisible(state)
+	if state.scroll != 0 {
